// Top-level category ordering (position in _category_.json)
const TOP_LEVEL_ORDER = [
  '',                           // 1 — docs root
  'tutorial',                   // 2
  'ui_help_doc',                // 3
  'QA',                         // 4
  'third_party_software_access',// 5
  'plugins',                    // 6
  'SDK',                        // 7
  'product_certification',      // 8
  'reborn_access',              // 9
];

// ─── Helpers ─────────────────────────────────────────────────────────────────

function readFrontMatter(filePath) {
  const raw = readFileSync(filePath, 'utf-8');
  const m = raw.match(/^---\n([\s\S]*?)\n---/);
  if (!m) return { body: raw, data: {} };
  const data = {};
  for (const line of m[1].split('\n')) {
    const kv = line.match(/^(\w[\w-]*):\s*(.*)/);
    if (kv) data[kv[1]] = kv[2].trim().replace(/^['"]|['"]$/g, '');
  }
  return { body: raw.slice(m[0].length), data, raw, fmBlock: m[1], fmStart: m.index, fmEnd: m.index + m[0].length };
}

function writeWithSidebarPosition(filePath, position) {
  const fm = readFrontMatter(filePath);
  if (fm.data.sidebar_position !== undefined) {
    console.log(`  [skip] ${relative(ROOT, filePath)} — already has sidebar_position`);
    return;
  }

  // Insert sidebar_position right after the opening --- line
  const newFM = `---\nsidebar_position: ${position}\n${fm.fmBlock}\n---`;
  const newContent = newFM + fm.body;
  writeFileSync(filePath, newContent);
  console.log(`  [ok]   ${relative(ROOT, filePath)} — sidebar_position: ${position}`);
}

function createCategoryJson(dir, locale) {
  const catKey = relative(DOCS, dir).replace(/\\/g, '/');
  const cat = CATEGORIES[catKey];
  if (!cat) {
    console.log(`  [warn] No CATEGORY entry for "${catKey}"`);
    return;
  }
  const lc = cat[locale];
  if (!lc) {
    console.log(`  [warn] No ${locale} entry for "${catKey}"`);
    return;
  }

  const idx = TOP_LEVEL_ORDER.indexOf(catKey);
  const position = idx >= 0 ? idx + 1 : 99;

  const json = {
    label: lc.label,
    position,
    collapsed: lc.collapsed,
  };
  if (lc.link) json.link = lc.link;

  writeFileSync(join(dir, '_category_.json'), JSON.stringify(json, null, 2) + '\n');
  console.log(`  [ok]   ${relative(ROOT, dir)}/_category_.json (${locale}) — "${lc.label}"`);
}

// ─── Main ────────────────────────────────────────────────────────────────────

console.log('=== Step 1: Create English _category_.json files ===\n');

// Recursively walk docs/ and create _category_.json for each directory
function walkDirs(dir) {
  for (const entry of readdirSync(dir, { withFileTypes: true })) {
    if (!entry.isDirectory()) continue;
    const full = join(dir, entry.name);
    createCategoryJson(full, 'en');
    walkDirs(full);
  }
}

createCategoryJson(DOCS, 'en');  // root
walkDirs(DOCS);

console.log('\n=== Step 2: Add sidebar_position to English .md files ===\n');

// Recursively walk docs/ and add sidebar_position to each .md
function walkDocs(dir) {
  for (const entry of readdirSync(dir, { withFileTypes: true })) {
    const full = join(dir, entry.name);
    if (entry.isDirectory()) {
      walkDocs(full);
    } else if (entry.name.endsWith('.md') || entry.name.endsWith('.mdx')) {
      const relPath = relative(DOCS, full).replace(/\\/g, '/').replace(/\.mdx?$/, '');
      const pos = POSITIONS[relPath];
      if (pos !== undefined) {
        writeWithSidebarPosition(full, pos);
      } else {
        console.log(`  [warn] No position for: ${relPath} — using 99`);
        writeWithSidebarPosition(full, 99);
      }
    }
  }
}
walkDocs(DOCS);

console.log('\n=== Step 3: Create translated _category_.json in i18n dirs ===\n');

const LOCALES = ['zh-Hans', 'ja', 'zh-Hant'];
const I18N_DOCS = 'docusaurus-plugin-content-docs/current';

for (const locale of LOCALES) {
  const base = join(I18N, locale, I18N_DOCS);

  // Root
  const rootDir = join(base);
  if (!existsSync(rootDir)) mkdirSync(rootDir, { recursive: true });
  const rootCat = CATEGORIES[''][locale];
  if (rootCat) {
    const idx = TOP_LEVEL_ORDER.indexOf('');
    const position = idx >= 0 ? idx + 1 : 1;
    const json = { label: rootCat.label, position, collapsed: rootCat.collapsed };
    if (rootCat.link) json.link = rootCat.link;
    writeFileSync(join(rootDir, '_category_.json'), JSON.stringify(json, null, 2) + '\n');
    console.log(`  [ok]   i18n/${locale}/.../_category_.json — "${rootCat.label}"`);
  }

  // Subdirectories
  for (const catKey of Object.keys(CATEGORIES)) {
    if (catKey === '') continue;
    const dir = join(base, catKey);
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
    const cat = CATEGORIES[catKey][locale];
    if (!cat) continue;

    const idx = TOP_LEVEL_ORDER.indexOf(catKey);
    const position = idx >= 0 ? idx + 1 : 99;
    const json = { label: cat.label, position, collapsed: cat.collapsed };
    if (cat.link) json.link = cat.link;
    writeFileSync(join(dir, '_category_.json'), JSON.stringify(json, null, 2) + '\n');
    console.log(`  [ok]   i18n/${locale}/.../${catKey}/_category_.json — "${cat.label}"`);
  }
}

console.log('\n=== Step 4: Add sidebar_position to i18n .md files ===\n');

for (const locale of LOCALES) {
  const base = join(I18N, locale, I18N_DOCS);
  if (!existsSync(base)) {
    console.log(`  [skip] i18n/${locale}/... — directory not found`);
    continue;
  }
  console.log(`  --- ${locale} ---`);
  walkI18nDocs(base, base);
}

function walkI18nDocs(base, dir) {
  for (const entry of readdirSync(dir, { withFileTypes: true })) {
    const full = join(dir, entry.name);
    if (entry.isDirectory()) {
      if (entry.name === 'current') continue; // skip nested current
      walkI18nDocs(base, full);
    } else if (entry.name.endsWith('.md') || entry.name.endsWith('.mdx')) {
      const relPath = relative(base, full).replace(/\\/g, '/').replace(/\.mdx?$/, '');
      const pos = POSITIONS[relPath];
      if (pos !== undefined) {
        writeWithSidebarPosition(full, pos);
      } else {
        // Extra file not in English docs (e.g. tutorial/temp.md in ja)
        console.log(`  [warn] No position for i18n file: ${relPath} → using 99`);
        writeWithSidebarPosition(full, 99);
      }
    }
  }
}

console.log('\n=== Done! ===');
